function meanAggregator(neighbors, features) {
  // Efficient mean aggregation for GraphSAGE
  // Implements sparse matrix operations with quantized weights
  let sum = new Float32Array(features[0].length);
  let count = 0;

  for (let i = 0; i < neighbors.length; i++) {
    const neighborIdx = neighbors[i];
    if (neighborIdx < features.length) {
      for (let j = 0; j < sum.length; j++) {
        sum[j] += features[neighborIdx][j];
      }
      count++;
    }
  }

  // Apply temporal decay and quantization
  const decayFactor = 0.95;
  for (let j = 0; j < sum.length; j++) {
    sum[j] = (sum[j] / count) * decayFactor;
    sum[j] = Math.round(sum[j] * 255) / 255; // 8-bit quantization
  }

  return sum;
}
```

