// Baseline anomaly detector: simple z-score on rolling means
function rollingStats(values, w){
  const means=[]; const stds=[];
  for(let i=0;i<values.length;i++){
    const start=Math.max(0,i-w+1);
    const window = values.slice(start,i+1);
    const m = window.reduce((a,b)=>a+b,0)/window.length;
    const v = window.reduce((acc,v)=>acc+(v-m)*(v-m),0)/(window.length);
    means[i]=m; stds[i]=Math.sqrt(v);
  }
  return {means,stds};
}
```

