```javascript
function psi(expected, actual, buckets = 10) {
  const epsilon = 1e-7;
  const allValues = [...expected, ...actual];
  const min = Math.min(...allValues);
  const max = Math.max(...allValues);
  const range = (max - min) / buckets;

  const expectedBuckets = new Array(buckets).fill(0);
  const actualBuckets = new Array(buckets).fill(0);

  for (const v of expected) {
    const bucket = Math.min(Math.floor((v - min) / range), buckets - 1);
    expectedBuckets[bucket]++;
  }

  for (const v of actual) {
    const bucket = Math.min(Math.floor((v - min) / range), buckets - 1);
    actualBuckets[bucket]++;
  }

  let psiValue = 0;
  for (let i = 0; i < buckets; i++) {
    const e = (expectedBuckets[i] + epsilon) / expected.length;
    const a = (actualBuckets[i] + epsilon) / actual.length;
    psiValue += (a - e) * Math.log(a / e);
  }

  return psiValue;
}

function detectDrift(featureName, trainData, liveData) {
  const score = psi(trainData, liveData);
  const status = score < 0.1 ? 'stable' : score < 0.2 ? 'moderate' : 'high';
  console.log(`Feature ${featureName}: PSI=${score.toFixed(3)} (${status})`);
  return { score, status, shouldAlert: score >= 0.2 };
}

